const email = $input.first().json;
const subject = email.subject || '';
const body = email.text || email.html || '';
const from = email.from?.value?.[0]?.address || email.from || '';

// Check if this is a property listing email
const propertyKeywords = ['for sale', 'listing', 'property', 'bedroom', 'bathroom', 'R ', 'price', 'asking', 'offers from', 'ne property', 'house', 'apartment', 'flat'];
const isPropertyEmail = propertyKeywords.some(kw => 
  subject.toLowerCase().includes(kw.toLowerCase()) || 
  body.toLowerCase().includes(kw.toLowerCase())
);

if (!isPropertyEmail) {
  return [{ json: { skip: true, reason: 'Not a property listing email', subject } }];
}

// Extract price
const pricePatterns = [
  /R\s?([\d][\d\s,\.]{2,})/g,
  /(?:price|asking|offers?(?:\s+from)?)\s*:?\s*R?\s?([\d][\d\s,\.]{2,})/gi,
  /([\d\.]+)\s*million/gi
];

let price = 0;
for (const pattern of pricePatterns) {
  const match = body.match(pattern);
  if (match) {
    let priceStr = match[0].replace(/[R\s,price:askingofferfrom]/gi, '').trim();
    if (priceStr.toLowerCase().includes('million') || priceStr.toLowerCase().includes('m')) {
      price = parseFloat(priceStr) * 1000000;
    } else {
      price = parseFloat(priceStr.replace(/[^\d.]/g, ''));
    }
    if (price > 50000 && price < 200000000) break;
  }
}

// Extract bedrooms
const bedroomMatch = body.match(/(\d+)\s*(?:bed(?:room)?s?|br)/i);
const bedrooms = bedroomMatch ? parseInt(bedroomMatch[1]) : 0;

// Extract bathrooms
const bathroomMatch = body.match(/(\d+)\s*(?:bath(?:room)?s?|ba)/i);
const bathrooms = bathroomMatch ? parseInt(bathroomMatch[1]) : 0;

// Extract area/size
const sizeMatch = body.match(/(\d+)\s*(?:m2|sqm|square\s*met)/i);
const size = sizeMatch ? parseFloat(sizeMatch[1]) : 0;

// Extract property type
let propertyType = 'unknown';
const bodyLower = body.toLowerCase();
if (bodyLower.includes('apartment') || bodyLower.includes('flat')) propertyType = 'apartment';
else if (bodyLower.includes('townhouse')) propertyType = 'townhouse';
else if (bodyLower.includes('plot') || bodyLower.includes('vacant land')) propertyType = 'plot';
else if (bodyLower.includes('house') || bodyLower.includes('home') || bodyLower.includes('dwelling')) propertyType = 'house';
else if (bodyLower.includes('farm')) propertyType = 'farm';

// Extract URL from email
const urlMatch = body.match(/https?:\/\/[^\s"<>]+(?:property|listing|realestate|estate)[^\s"<>]*/i);
const url = urlMatch ? urlMatch[0] : '';

const listingId = `email_${Buffer.from(email.messageId || Date.now().toString()).toString('base64').substring(0, 20)}`;

return [{
  json: {
    skip: false,
    listing_id: listingId,
    title: subject || 'Email Property Listing',
    description: body.substring(0, 2000),
    price: price,
    price_currency: 'ZAR',
    bedrooms: bedrooms,
    bathrooms: bathrooms,
    size_sqm: size,
    property_type: propertyType,
    source: 'email',
    sender_email: from,
    url: url,
    email_date: email.date || new Date().toISOString(),
    scraped_at: new Date().toISOString(),
    suburb: '',
    city: '',
    province: '',
    status: 'pending_review',
    agent_name: '',
    agent_phone: '',
    images: []
  }
}];

